package main

import (
	"fmt"
	"time"
)

func main() {
	tick := time.Tick(100 * time.Millisecond)
	boom := time.After(500 * time.Millisecond)

	for {
		select {
		case <-tick:
			fmt.Println("Тик!")
		case <-boom:
			fmt.Println("БАМ! 🎉")
			return
		default:
			fmt.Println("...ожидание...")
			time.Sleep(50 * time.Millisecond)
		}
	}
}

