package main

import (
	"fmt"
	"sync"
)

type Counter struct {
	mu sync.Mutex
	value int
}

func (c *Counter) Increment() {
	c.mu.Lock()
	c.value++
	c.mu.Unlock()
}

func main() {
	var c Counter
	for i := 0; i < 100; i++ {
		go c.Increment()
	}
	// для примера ждём
	fmt.Println("Итог:", c.value)
}

